"use client";

import { useState, useEffect } from "react";

const MyOrders = () => {
  const [orders, setOrders] = useState<any[]>([]);
  const [user, setUser] = useState<{ email: string; phone: string } | null>(null);

  useEffect(() => {
    const storedUser = localStorage.getItem("user");
    const storedOrders = localStorage.getItem("orders");

    if (storedUser) {
      const parsedUser = JSON.parse(storedUser);
      setUser(parsedUser);

      if (storedOrders) {
        const allOrders = JSON.parse(storedOrders);

        // Filter orders for current user
        const userOrders = allOrders.filter(
          (order: any) => order.userEmail === parsedUser.email
        );

        // Reverse to show latest orders first
        setOrders(userOrders.reverse());
      }
    }
  }, []);

  if (!user) {
    return (
      <div className="max-w-4xl mx-auto p-6 text-center">
        <p className="text-red-500 text-lg font-semibold">
          Please sign in to view your orders.
        </p>
      </div>
    );
  }

  if (orders.length === 0) {
    return (
      <div className="max-w-4xl mx-auto p-6 text-center">
        <p className="text-gray-500 text-lg">No orders found.</p>
      </div>
    );
  }

  return (
    <div className="max-w-5xl mx-auto p-6">
      <h2 className="text-3xl font-bold mb-6">My Orders</h2>
      <div className="space-y-6">
        {orders.map((order, index) => (
          <div key={index} className="border rounded-lg shadow-md p-6 bg-white">
            {/* Order Header */}
            <div className="flex justify-between items-center mb-4">
              <div>
                <h3 className="text-xl font-bold">Order #{orders.length - index}</h3>
                {/* ✅ Order timestamp */}
                {order.orderTime && (
                <p className="text-gray-500 text-sm">
  📅 Placed on: {order.orderTime ? new Date(order.orderTime).toLocaleString() : "N/A"}
</p>
                )}
              </div>
              <span className="text-gray-500">{order.paymentMethod}</span>
            </div>

            {/* Contact & Shipping Info */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-4">
              <div>
                <h4 className="font-semibold text-gray-700 mb-1">Contact Info</h4>
                <p>📧 Email: {order.userEmail}</p>
                <p>📞 Phone: {order.phone}</p>
              </div>
              <div>
                <h4 className="font-semibold text-gray-700 mb-1">Shipping Address</h4>
                <p>{order.address}</p>
                <p>{order.pincode}</p>
                {order.location && (
                  <a
                    href={order.location}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="text-blue-600 hover:underline"
                  >
                    View Location
                  </a>
                )}
              </div>
            </div>

            {/* Services Ordered */}
            <div className="mb-4">
              <h4 className="font-semibold text-gray-700 mb-2">Services Ordered:</h4>
              <div className="border rounded-md divide-y">
                {order.cart.map((item: any, i: number) => (
                  <div
                    key={i}
                    className="flex justify-between p-3 hover:bg-gray-50 transition"
                  >
                    <span>{item.name}</span>
                    <span>₹{parseFloat(item.price).toFixed(2)}</span>
                  </div>
                ))}
              </div>
            </div>

            {/* Total Amount */}
            <div className="flex justify-end mt-4 text-xl font-bold text-green-700">
              Total: ₹{parseFloat(order.totalPrice).toFixed(2)}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default MyOrders;

